#!/bin/bash
# helpers.sh - Consolidated shared functions for the unified install framework.
# Sourced by install.sh and (optionally) thin-wrapper scripts during migration.
#
# Secret strategy: secrets live ONLY in Kubernetes. Auto-generated by install
# scripts. Legacy kubesecrets.yaml support (monitoring_apply_secret_from_kubesecrets)
# is deprecated in bin/monitoring-common.sh.
# no on-disk secret templates, no static secret files.

# shellcheck disable=SC2034,SC2154

# ── Globals ──────────────────────────────────────────────────────────────────

GENESTACK_BASE_DIR="${GENESTACK_BASE_DIR:-/opt/genestack}"
GENESTACK_OVERRIDES_DIR="${GENESTACK_OVERRIDES_DIR:-/etc/genestack}"
GENESTACK_SERVICES_DIR="${GENESTACK_SERVICES_DIR:-$(cd "$(dirname "$0")" && pwd)/services}"
GENESTACK_INSTALL_BIN="${GENESTACK_INSTALL_BIN:-$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)/install.sh}"
GENESTACK_HELPERS_DIR="${GENESTACK_HELPERS_DIR:-$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)}"
GENESTACK_COMPONENTS_FILE="${GENESTACK_COMPONENTS_FILE:-${GENESTACK_OVERRIDES_DIR}/openstack-components.yaml}"
GENESTACK_SERVICE_CONFIG_OVERRIDES_DIR="${GENESTACK_SERVICE_CONFIG_OVERRIDES_DIR:-${GENESTACK_OVERRIDES_DIR}/service-configs}"
CHART_VERSIONS_FILE="${GENESTACK_OVERRIDES_DIR}/helm-chart-versions.yaml"
HELM_KUSTOMIZE_CMD="${GENESTACK_OVERRIDES_DIR}/kustomize/kustomize.sh"
KUBECTL_BIN="${KUBECTL_BIN:-sudo kubectl}"
YQ_BIN="yq"

# Array to track temp files for cleanup
TMP_FILES=()

# ── Tool Validation ──────────────────────────────────────────────────────────

validate_tools() {
    local missing=()
    local REQUIRED=(kubectl yq helm)
    for tool in "${REQUIRED[@]}"; do
        if ! command -v "$tool" &>/dev/null 2>&1; then
            missing+=("$tool")
        fi
    done
    if [[ ${#missing[@]} -gt 0 ]]; then
        log_error "Required tool(s) not found: ${missing[*]}."
        log_error "Install them before running install.sh."
        exit 1
    fi

    # Optional tool checks
    if ! command -v base64 &>/dev/null 2>&1; then
        log_error "Required tool 'base64' not found."
        exit 1
    fi
    _detect_os_base64_flag
}

_detect_os_base64_flag() {
    if [[ "$(uname -s)" == "Darwin" ]]; then
        BASE64_FLAG="-d"
    else
        BASE64_FLAG="-d"  # GNU base64 uses -d; BSD uses -d too, but -w0 differs
    fi
}

decode_base64() {
    echo "$1" | base64 $BASE64_FLAG 2>/dev/null
}

encode_base64_single_line() {
    printf '%s' "$1" | base64 | tr -d '\n'
}

# ── Logging ──────────────────────────────────────────────────────────────────

log_info()     { echo "[INFO]  $*" >&2; }
log_warn()     { echo "[WARN]  $*" >&2; }
log_error()    { echo "[ERROR] $*" >&2; }
log_header()   { echo ""; echo "========================================"; echo "  $*"; echo "========================================" >&2; }

# ── CLI Parsing ──────────────────────────────────────────────────────────────

parse_cli() {
    # Consumes all options, sets:
    #   CL_ROTATE_SECRETS   -- bool
    #   CL_CHECK_SECRETS    -- bool
    #   CL_FORCE_YES        -- bool
    #   CL_SERVICE          -- service name (via --service)
    #   CL_EXTRA_HELM_ARGS  -- array of leftover --* args for helm
    #   CL_OVERRIDE_VERSION -- explicit version override
    CL_ROTATE_SECRETS=0
    CL_CHECK_SECRETS=0
    CL_FORCE_YES=0
    CL_SERVICE=""
    CL_EXTRA_HELM_ARGS=()
    CL_OVERRIDE_VERSION=""

    while [[ $# -gt 0 ]]; do
        case "$1" in
            --rotate-secrets)
                CL_ROTATE_SECRETS=1; shift ;;
            --check-secrets)
                CL_CHECK_SECRETS=1; shift ;;
            --yes-i-really-want-to)
                CL_FORCE_YES=1; shift ;;
            --version)
                shift; CL_OVERRIDE_VERSION="$1"; shift ;;
            --service)
                shift; CL_SERVICE="$1"; shift ;;
            --help|-h|help)
                _cli_help; exit 0 ;;
            *)
                # If we already have the service flag, remaining args are helm extras
                if [[ -n "$CL_SERVICE" ]]; then
                    CL_EXTRA_HELM_ARGS+=("$1")
                else
                    log_error "Unexpected argument: $1. Usage: install.sh --service <service-name> [OPTIONS]"
                    exit 1
                fi
                shift ;;
        esac
    done

    if [[ -z "$CL_SERVICE" ]]; then
        log_error "Service name required. Usage: install.sh --service <service-name>"
        exit 1
    fi
}

_cli_help() {
    cat <<'EOF'
Usage:
  install.sh --service <name> [--rotate-secrets] [--check-secrets] [--yes-i-really-want-to] [HELM_FLAGS...]

Options:
  --rotate-secrets              Rotate service-owned secrets and reinstall impacted services
  --check-secrets               Print resolved secrets without installing
  --yes-i-really-want-to        Auto-approve all installer confirmation prompts
  --version <ver>               Override chart version
  --service <name>              (required) service name
  --help, -h                    Show this help

Remaining --* flags after the service name are passed through to helm upgrade --install.

Examples:
  # basic install
  install.sh --service nova

  # pass helm flags (--wait tells helm to wait for resources, --timeout sets max wait)
  install.sh --service nova --wait --timeout 30m

  # helm dry-run renders templates without applying (helm's built-in --dry-run)
  install.sh --service nova --dry-run

  # --dry-run as --set value
  install.sh --service nova --set conf.nova.some_option="dry-run"

  # rotate service-owned secrets and reinstall impacted services
  install.sh --rotate-secrets --service nova

  # auto-approve all prompts
  install.sh --yes-i-really-want-to --rotate-secrets --service nova

  # check what secrets will be used (fails if any are missing)
  install.sh --check-secrets --service nova
EOF
}

stdin_is_tty() {
    [[ -t 0 ]]
}

prompt_confirm() {
    local prompt="${1:-Continue?}"
    local reply

    if [[ "${CL_FORCE_YES:-0}" -eq 1 ]]; then
        log_info "Auto-approving prompt: ${prompt}"
        return 0
    fi

    printf '%s [y/N]: ' "$prompt" >&2
    read -r reply
    case "$reply" in
        y|Y|yes|YES)
            return 0
            ;;
        *)
            return 1
            ;;
    esac
}

rotation_collect_owned_secrets() {
    local svc_yaml_content="$1"
    local count i
    local seen=()

    count=$(echo "$svc_yaml_content" | yq e '.secrets | length' - 2>/dev/null)
    [[ "$count" == "null" || -z "$count" ]] && count=0

    for (( i=0; i<count; i++ )); do
        local source_secret source_namespace rotate_with_service replace_count j rep_secret rep_namespace rep_rotate_with_service
        source_secret=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_secret // \"\"" -)
        source_namespace=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_namespace // .service.namespace // \"openstack\"" -)
        rotate_with_service=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].rotate_with_service // false" -)
        if [[ "$rotate_with_service" == "true" && -n "$source_secret" ]]; then
            local owned_secret="${source_namespace}/${source_secret}"
            if [[ " ${seen[*]:-} " != *" ${owned_secret} "* ]]; then
                seen+=("$owned_secret")
                echo "$owned_secret"
            fi
        fi

        replace_count=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace | length // 0" - 2>/dev/null)
        [[ "$replace_count" == "null" || -z "$replace_count" ]] && replace_count=0
        for (( j=0; j<replace_count; j++ )); do
            rep_secret=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[${j}].secret // \"\"" -)
            rep_namespace=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[${j}].namespace // .service.namespace // \"openstack\"" -)
            rep_rotate_with_service=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[${j}].rotate_with_service // false" -)
            if [[ "$rep_rotate_with_service" == "true" && -n "$rep_secret" ]]; then
                local owned_replace_secret="${rep_namespace}/${rep_secret}"
                if [[ " ${seen[*]:-} " != *" ${owned_replace_secret} "* ]]; then
                    seen+=("$owned_replace_secret")
                    echo "$owned_replace_secret"
                fi
            fi
        done
    done
}

build_secret_helm_arg() {
    local helm_flag="$1"
    local helm_key="$2"
    local value="$3"

    case "$helm_flag" in
        --set-file)
            local tmp_f
            tmp_f=$(mk_tmp_file)
            echo -n "$value" > "$tmp_f"
            printf '%s\t%s=%s\n' "$helm_flag" "$helm_key" "$tmp_f"
            ;;
        --set-string|--set)
            printf '%s\t%s=%s\n' "$helm_flag" "$helm_key" "$value"
            ;;
        *)
            log_warn "Unsupported helm_flag '${helm_flag}' for '${helm_key}', defaulting to --set."
            printf '%s\t%s=%s\n' "--set" "$helm_key" "$value"
            ;;
    esac
}

secret_args_to_helm_tokens() {
    local set_args_raw="$1"

    while IFS=$'\t' read -r flag arg; do
        [[ -z "$flag" || -z "$arg" ]] && continue
        printf '%s\n%s\n' "$flag" "$arg"
    done <<< "$set_args_raw"
}

build_post_renderer_args() {
    local svc_yaml_content="$1"
    local service_name="$2"

    local kustomize_enabled raw_KE overlay_path
    raw_KE=$(echo "$svc_yaml_content" | yq e '.kustomize.enabled' -)
    if [[ "$raw_KE" == "false" ]]; then
        kustomize_enabled="false"
    else
        kustomize_enabled="true"
    fi

    overlay_path=$(echo "$svc_yaml_content" | yq e '.kustomize.overlay_path // "${service_name}/overlay"' -)
    overlay_path="${overlay_path//\$\{service_name\}/$service_name}"

    if [[ "$kustomize_enabled" == "true" && -f "$HELM_KUSTOMIZE_CMD" ]]; then
        printf '%s\n%s\n%s\n%s\n' \
            "--post-renderer" \
            "${HELM_KUSTOMIZE_CMD}" \
            "--post-renderer-args" \
            "${overlay_path}"
    fi
}

resolve_helm_timeout() {
    local svc_yaml_content="$1"
    local timeout
    timeout=$(echo "$svc_yaml_content" | yq e '.helm.timeout // "120m"' - 2>/dev/null)
    [[ -z "$timeout" || "$timeout" == "null" || "$timeout" == "~" ]] && timeout="120m"
    echo "$timeout"
}

build_helm_upgrade_install_cmd() {
    local release_name="$1"
    local chart_path="$2"
    local namespace="$3"
    local version="$4"
    local timeout="$5"
    local override_lines="$6"
    local set_args_raw="$7"
    local post_renderer_args="$8"
    shift 8
    local extra_args=("$@")

    local helm_cmd=()
    helm_cmd+=(helm upgrade --install "$release_name" "$chart_path")

    [[ -n "$version" ]] && helm_cmd+=("--version=${version}")

    helm_cmd+=(--namespace="$namespace")
    helm_cmd+=(--timeout "$timeout")
    helm_cmd+=(--create-namespace)

    if [[ -n "$override_lines" ]]; then
        while IFS= read -r token; do
            [[ -z "$token" ]] && continue
            helm_cmd+=("$token")
        done <<< "$override_lines"
    fi

    if [[ -n "$set_args_raw" ]]; then
        while IFS= read -r token; do
            [[ -z "$token" ]] && continue
            helm_cmd+=("$token")
        done < <(secret_args_to_helm_tokens "$set_args_raw")
    fi

    if declare -p helm_set_args >/dev/null 2>&1 && [[ ${#helm_set_args[@]} -gt 0 ]]; then
        helm_cmd+=("${helm_set_args[@]}")
    fi

    if [[ -n "$post_renderer_args" ]]; then
        while IFS= read -r token; do
            [[ -z "$token" ]] && continue
            helm_cmd+=("$token")
        done <<< "$post_renderer_args"
    fi

    if [[ ${#extra_args[@]} -gt 0 ]]; then
        helm_cmd+=("${extra_args[@]}")
    fi

    printf '%s\n' "${helm_cmd[@]}"
}

append_helm_set_arg() {
    local helm_key="$1"
    local value="$2"

    if ! declare -p helm_set_args >/dev/null 2>&1; then
        helm_set_args=()
    fi

    helm_set_args+=("--set" "${helm_key}=${value}")
}

run_service_actions() {
    local svc_yaml_content="$1"
    local actions_path="$2"
    local service_name="$3"
    local count i

    count=$(echo "$svc_yaml_content" | yq e "${actions_path} | length // 0" - 2>/dev/null)
    [[ -z "$count" || "$count" == "null" ]] && count=0

    for (( i=0; i<count; i++ )); do
        run_service_action "$svc_yaml_content" "${actions_path}" "$i" "$service_name" || return $?
    done
}

run_service_action() {
    local svc_yaml_content="$1"
    local actions_path="$2"
    local action_index="$3"
    local service_name="$4"
    local action_type

    action_type=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].type // \"\"" -)

    case "$action_type" in
        monitoring_grafana_db_secret_bootstrap)
            # shellcheck source=/dev/null
            source "${GENESTACK_HELPERS_DIR}/monitoring-common.sh"
            monitoring_ensure_grafana_db_secret
            ;;
        kube_ovn_master_discovery)
            local node_label master_nodes_helm_key replica_count_helm_key master_nodes_raw
            node_label=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].node_label // \"kube-ovn/role=master\"" -)
            master_nodes_helm_key=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].master_nodes_helm_key // \"\"" -)
            replica_count_helm_key=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].replica_count_helm_key // \"\"" -)

            master_nodes_raw=$($KUBECTL_BIN get nodes -l "$node_label" \
                -o jsonpath='{range .items[*]}{range .status.addresses[?(@.type=="InternalIP")]}{.address}{"\n"}{end}{end}' \
                2>/dev/null || true)
            MASTER_NODE_COUNT=$(printf '%s\n' "$master_nodes_raw" | sed '/^$/d' | wc -l | tr -d ' ')
            MASTER_NODES=$(printf '%s\n' "$master_nodes_raw" | sed '/^$/d' | paste -sd, - | sed 's/,/\\,/g')
            export MASTER_NODE_COUNT MASTER_NODES

            if [[ -n "$master_nodes_helm_key" && -n "$MASTER_NODES" ]]; then
                append_helm_set_arg "$master_nodes_helm_key" "$MASTER_NODES"
            fi
            if [[ -n "$replica_count_helm_key" && -n "$MASTER_NODE_COUNT" ]]; then
                append_helm_set_arg "$replica_count_helm_key" "$MASTER_NODE_COUNT"
            fi
            ;;
        detect_kube_ovn_tls)
            local ovn_namespace
            ovn_namespace=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].namespace // \"kube-system\"" -)
            detect_kube_ovn_tls "$ovn_namespace"
            ;;
        ensure_ovn_client_tls_secret)
            local src_ns dst_ns src_name dst_name
            src_ns=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].source_namespace // \"kube-system\"" -)
            dst_ns=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].target_namespace // .service.namespace // \"openstack\"" -)
            src_name=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].source_secret // \"kube-ovn-tls\"" -)
            dst_name=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].target_secret // \"ovn-client-tls\"" -)
            ensure_ovn_client_tls_secret "$src_ns" "$dst_ns" "$src_name" "$dst_name"
            ;;
        ovn_connection_set_args)
            local entry_count j helm_key env_name env_value
            entry_count=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].entries | length // 0" - 2>/dev/null)
            [[ -z "$entry_count" || "$entry_count" == "null" ]] && entry_count=0
            for (( j=0; j<entry_count; j++ )); do
                helm_key=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].entries[${j}].helm_key // \"\"" -)
                env_name=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].entries[${j}].env // \"\"" -)
                [[ -z "$helm_key" || -z "$env_name" ]] && continue
                env_value="${!env_name:-}"
                if [[ -z "$env_value" ]]; then
                    log_warn "Skipping OVN Helm arg '${helm_key}' for '${service_name}' because ${env_name} is empty."
                    continue
                fi
                append_helm_set_arg "$helm_key" "$env_value"
            done
            ;;
        rollout_status)
            local namespace workload timeout
            namespace=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].namespace // .service.namespace // \"openstack\"" -)
            workload=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].workload // \"\"" -)
            timeout=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].timeout // \"300s\"" -)
            [[ -z "$workload" ]] && {
                log_error "Missing workload for rollout_status action in '${service_name}'."
                return 1
            }
            $KUBECTL_BIN rollout status "$workload" --namespace "$namespace" --timeout="$timeout"
            ;;
        get_by_label_optional)
            local namespace resource selector not_found_message
            namespace=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].namespace // .service.namespace // \"openstack\"" -)
            resource=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].resource // \"pods\"" -)
            selector=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].selector // \"\"" -)
            not_found_message=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].not_found_message // \"\"" -)

            if [[ -n "$selector" ]]; then
                if ! $KUBECTL_BIN get "$resource" --namespace "$namespace" -l "$selector" >/dev/null 2>&1; then
                    [[ -n "$not_found_message" ]] && echo "$not_found_message"
                fi
            elif ! $KUBECTL_BIN get "$resource" --namespace "$namespace" >/dev/null 2>&1; then
                [[ -n "$not_found_message" ]] && echo "$not_found_message"
            fi
            ;;
        namespace_resource_dump_if_pods_present)
            local namespace resource_count j resource_name
            namespace=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].namespace // .service.namespace // \"openstack\"" -)
            if $KUBECTL_BIN get pods --namespace "$namespace" >/dev/null 2>&1; then
                echo "Resources in ${namespace}:"
                resource_count=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].resources | length // 0" - 2>/dev/null)
                [[ -z "$resource_count" || "$resource_count" == "null" || "$resource_count" == "0" ]] && resource_count=2
                if [[ "$resource_count" -eq 2 ]] && [[ "$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].resources" - 2>/dev/null)" == "null" ]]; then
                    $KUBECTL_BIN get pods --namespace "$namespace"
                    $KUBECTL_BIN get svc --namespace "$namespace"
                else
                    for (( j=0; j<resource_count; j++ )); do
                        resource_name=$(echo "$svc_yaml_content" | yq e "${actions_path}[${action_index}].resources[${j}] // \"\"" -)
                        [[ -z "$resource_name" || "$resource_name" == "null" ]] && continue
                        $KUBECTL_BIN get "$resource_name" --namespace "$namespace"
                    done
                fi
            fi
            ;;
        "")
            return 0
            ;;
        *)
            log_error "Unsupported action type '${action_type}' in '${service_name}'."
            return 1
            ;;
    esac
}

resolve_secret_value_from_action() {
    local svc_yaml_content="$1"
    local secret_index="$2"
    local dry_run="$3"
    local action_type namespace secret_name data_key value=""

    action_type=$(echo "$svc_yaml_content" | yq e ".secrets[${secret_index}].value_from.type // \"\"" -)

    case "$action_type" in
        secret_data)
            namespace=$(echo "$svc_yaml_content" | yq e ".secrets[${secret_index}].value_from.namespace // .service.namespace // \"openstack\"" -)
            secret_name=$(echo "$svc_yaml_content" | yq e ".secrets[${secret_index}].value_from.secret_name // \"\"" -)
            data_key=$(echo "$svc_yaml_content" | yq e ".secrets[${secret_index}].value_from.data_key // \"\"" -)

            if [[ -z "$secret_name" || -z "$data_key" ]]; then
                log_error "value_from.secret_data requires secret_name and data_key."
                return 1
            fi

            if [[ "$dry_run" -eq 1 ]]; then
                if ! secret_exists "$namespace" "$secret_name"; then
                    log_error "MISSING SECRET: ${namespace}/${secret_name}"
                    return 1
                fi
                value=$(secret_get "$namespace" "$secret_name" "$data_key")
                if [[ -z "$value" ]]; then
                    log_error "Missing secret data: ${namespace}/${secret_name}:${data_key}"
                    return 1
                fi
            else
                value=$(secret_get "$namespace" "$secret_name" "$data_key")
                if [[ -z "$value" ]]; then
                    log_error "Missing secret data: ${namespace}/${secret_name}:${data_key}"
                    return 1
                fi
            fi

            printf '%s' "$value"
            ;;
        "")
            return 1
            ;;
        *)
            log_error "Unsupported value_from action type '${action_type}'."
            return 1
            ;;
    esac
}

service_secret_is_explicit_ssh_keypair() {
    local svc_yaml_content="$1"
    local secret_name="$2"
    local secret_namespace="$3"

    service_secret_is_ssh_keypair "$svc_yaml_content" "$secret_name" "$secret_namespace"
}

service_secret_data_keys() {
    local svc_yaml_content="$1"
    local secret_name="$2"
    local secret_namespace="$3"

    echo "$svc_yaml_content" | yq e ".secrets[] | select(.source_secret == \"${secret_name}\" and ((.source_namespace // .service.namespace // \"openstack\") == \"${secret_namespace}\")) | .data_key" -
}

rotation_regenerate_owned_secret() {
    local svc_yaml_content="$1"
    local secret_namespace="$2"
    local secret_name="$3"

    if service_secret_is_explicit_ssh_keypair "$svc_yaml_content" "$secret_name" "$secret_namespace"; then
        local public_key_name private_key_name
        public_key_name=$(echo "$svc_yaml_content" | yq e ".secrets[] | select(.source_secret == \"${secret_name}\" and ((.source_namespace // .service.namespace // \"openstack\") == \"${secret_namespace}\") and (.data_key == \"public-key\" or .data_key == \"public_key\")) | .data_key" - | head -n1)
        private_key_name=$(echo "$svc_yaml_content" | yq e ".secrets[] | select(.source_secret == \"${secret_name}\" and ((.source_namespace // .service.namespace // \"openstack\") == \"${secret_namespace}\") and (.data_key == \"private-key\" or .data_key == \"private_key\")) | .data_key" - | head -n1)
        secret_ensure_ssh_keypair "$secret_namespace" "$secret_name" "$public_key_name" "$private_key_name"
        return 0
    fi

    if secret_name_is_rabbitmq_user_credentials "$secret_name"; then
        secret_ensure_rabbitmq_user_credentials "$secret_namespace" "$secret_name"
        return 0
    fi

    local key
    while IFS= read -r key; do
        [[ -z "$key" || "$key" == "null" ]] && continue
        secret_ensure "$secret_namespace" "$secret_name" "$key" "$(secret_generate 32)"
    done < <(service_secret_data_keys "$svc_yaml_content" "$secret_name" "$secret_namespace")
}

rotation_service_enabled() {
    local service_name="$1"
    local enabled

    if [[ ! -f "$GENESTACK_COMPONENTS_FILE" ]]; then
        return 0
    fi

    enabled=$(yq e ".components.${service_name}" "$GENESTACK_COMPONENTS_FILE" 2>/dev/null)

    case "$enabled" in
        true|\"true\")
            return 0
            ;;
        *)
            return 1
            ;;
    esac
}

rotation_collect_impacted_services() {
    local service_name="$1"
    shift
    local owned_secrets=("$@")
    local service_file
    local seen=()

    for service_file in "${GENESTACK_SERVICES_DIR}"/*.yaml; do
        [[ -f "$service_file" ]] || continue
        [[ "$(basename "$service_file")" == "example-service.yaml" ]] && continue

        local candidate_service candidate_yaml count i replace_count j
        candidate_yaml=$(load_service_config "$(basename "${service_file%.yaml}")")
        candidate_service=$(echo "$candidate_yaml" | yq e '.service.name // ""' -)
        [[ -z "$candidate_service" || "$candidate_service" == "null" ]] && continue
        rotation_service_enabled "$candidate_service" || continue

        count=$(echo "$candidate_yaml" | yq e '.secrets | length' - 2>/dev/null)
        [[ "$count" == "null" || -z "$count" ]] && count=0

        for (( i=0; i<count; i++ )); do
            local source_secret source_namespace candidate_ref matched_ref=0
            source_secret=$(echo "$candidate_yaml" | yq e ".secrets[${i}].source_secret // \"\"" -)
            source_namespace=$(echo "$candidate_yaml" | yq e ".secrets[${i}].source_namespace // .service.namespace // \"openstack\"" -)
            if [[ -n "$source_secret" ]]; then
                candidate_ref="${source_namespace}/${source_secret}"
                if array_contains "$candidate_ref" "${owned_secrets[@]}"; then
                    matched_ref=1
                fi
            fi

            if [[ "$matched_ref" -eq 0 ]]; then
                replace_count=$(echo "$candidate_yaml" | yq e ".secrets[${i}].replace | length // 0" - 2>/dev/null)
                [[ "$replace_count" == "null" || -z "$replace_count" ]] && replace_count=0
                for (( j=0; j<replace_count; j++ )); do
                    local rep_secret rep_namespace rep_ref
                    rep_secret=$(echo "$candidate_yaml" | yq e ".secrets[${i}].replace[${j}].secret // \"\"" -)
                    rep_namespace=$(echo "$candidate_yaml" | yq e ".secrets[${i}].replace[${j}].namespace // .service.namespace // \"openstack\"" -)
                    if [[ -n "$rep_secret" ]]; then
                        rep_ref="${rep_namespace}/${rep_secret}"
                        if array_contains "$rep_ref" "${owned_secrets[@]}"; then
                            matched_ref=1
                            break
                        fi
                    fi
                done
            fi

            if [[ "$matched_ref" -eq 1 ]]; then
                if [[ "$candidate_service" != "$service_name" ]] && \
                    ([[ ${#seen[@]} -eq 0 ]] || ! array_contains "$candidate_service" "${seen[@]}"); then
                    seen+=("$candidate_service")
                    echo "$candidate_service"
                fi
                break
            fi
        done
    done
}

array_contains() {
    local needle="$1"
    shift
    local item
    for item in "$@"; do
        [[ "$item" == "$needle" ]] && return 0
    done
    return 1
}

rotation_collect_resource_names_for_secret() {
    local api_resource="$1"
    local namespace="$2"
    local yq_expr="$3"

    $KUBECTL_BIN get "$api_resource" --namespace "$namespace" -o yaml 2>/dev/null \
        | yq e "$yq_expr" - 2>/dev/null || true
}

rotation_get_resource_field() {
    local api_resource="$1"
    local namespace="$2"
    local resource_name="$3"
    local yq_expr="$4"

    $KUBECTL_BIN get "$api_resource" "$resource_name" --namespace "$namespace" -o yaml 2>/dev/null \
        | yq e "$yq_expr" - 2>/dev/null || true
}

rotation_patch_resource_annotation() {
    local api_resource="$1"
    local namespace="$2"
    local resource_name="$3"
    local stamp
    stamp="$(date -u +%Y-%m-%dT%H:%M:%SZ)"

    $KUBECTL_BIN patch "$api_resource" "$resource_name" --namespace "$namespace" \
        --type merge \
        --patch "{\"metadata\":{\"annotations\":{\"genestack.osp/rotated-at\":\"${stamp}\"}}}" \
        >/dev/null
}

rotation_wait_for_resource_ready() {
    local api_resource="$1"
    local namespace="$2"
    local resource_name="$3"
    local timeout="${4:-300s}"

    if ! $KUBECTL_BIN wait --for=condition=Ready --timeout="$timeout" \
        "${api_resource}/${resource_name}" --namespace "$namespace" >/dev/null 2>&1; then
        log_warn "Timed out waiting for ${api_resource}/${resource_name} to report Ready."
        return 1
    fi

    return 0
}

rotation_wait_for_mariadb_user_password() {
    local namespace="$1"
    local user_resource_name="$2"
    local secret_name="$3"
    local timeout_seconds="${4:-300}"
    local username cluster_name password pod_name
    local elapsed=0

    username=$(rotation_get_resource_field "users.k8s.mariadb.com" "$namespace" "$user_resource_name" '.spec.name // .metadata.name')
    cluster_name=$(rotation_get_resource_field "users.k8s.mariadb.com" "$namespace" "$user_resource_name" '.spec.mariaDbRef.name // ""')
    password=$(secret_get "$namespace" "$secret_name" "password")
    pod_name="${cluster_name}-0"

    if [[ -z "$username" || "$username" == "null" || -z "$cluster_name" || "$cluster_name" == "null" || -z "$password" ]]; then
        log_warn "Unable to derive MariaDB readiness check inputs for ${namespace}/${user_resource_name}."
        return 1
    fi

    while (( elapsed < timeout_seconds )); do
        if $KUBECTL_BIN exec "$pod_name" --namespace "$namespace" -- bash -lc \
            "mariadb -h 127.0.0.1 -u\"${username}\" -p\"${password}\" -e 'select 1;' >/dev/null 2>&1" \
            >/dev/null 2>&1; then
            log_info "Verified MariaDB credentials for ${namespace}/${user_resource_name}."
            return 0
        fi
        sleep 5
        elapsed=$((elapsed + 5))
    done

    log_warn "Timed out waiting for MariaDB credentials to work for ${namespace}/${user_resource_name}."
    return 1
}

rotation_wait_for_rabbitmq_user_password() {
    local namespace="$1"
    local user_resource_name="$2"
    local secret_name="$3"
    local timeout_seconds="${4:-300}"
    local username cluster_name password pod_name
    local elapsed=0

    username=$(rotation_get_resource_field "users.rabbitmq.com" "$namespace" "$user_resource_name" '.status.username // .metadata.name')
    cluster_name=$(rotation_get_resource_field "users.rabbitmq.com" "$namespace" "$user_resource_name" '.spec.rabbitmqClusterReference.name // ""')
    password=$(secret_get "$namespace" "$secret_name" "password")
    pod_name="${cluster_name}-server-0"

    if [[ -z "$username" || "$username" == "null" || -z "$cluster_name" || "$cluster_name" == "null" || -z "$password" ]]; then
        log_warn "Unable to derive RabbitMQ readiness check inputs for ${namespace}/${user_resource_name}."
        return 1
    fi

    while (( elapsed < timeout_seconds )); do
        if $KUBECTL_BIN exec "$pod_name" --namespace "$namespace" -- bash -lc \
            "rabbitmqctl authenticate_user \"${username}\" \"${password}\" >/dev/null 2>&1" \
            >/dev/null 2>&1; then
            log_info "Verified RabbitMQ credentials for ${namespace}/${user_resource_name}."
            return 0
        fi
        sleep 5
        elapsed=$((elapsed + 5))
    done

    log_warn "Timed out waiting for RabbitMQ credentials to work for ${namespace}/${user_resource_name}."
    return 1
}

rotation_apply_rabbitmq_user_password() {
    local namespace="$1"
    local user_resource_name="$2"
    local secret_name="$3"
    local username cluster_name password pod_name

    username=$(rotation_get_resource_field "users.rabbitmq.com" "$namespace" "$user_resource_name" '.status.username // .metadata.name')
    cluster_name=$(rotation_get_resource_field "users.rabbitmq.com" "$namespace" "$user_resource_name" '.spec.rabbitmqClusterReference.name // ""')
    password=$(secret_get "$namespace" "$secret_name" "password")
    pod_name="${cluster_name}-server-0"

    if [[ -z "$username" || "$username" == "null" || -z "$cluster_name" || "$cluster_name" == "null" || -z "$password" ]]; then
        log_warn "Unable to derive RabbitMQ password update inputs for ${namespace}/${user_resource_name}."
        return 1
    fi

    log_info "Applying RabbitMQ password for ${namespace}/${user_resource_name} via broker update"
    $KUBECTL_BIN exec "$pod_name" --namespace "$namespace" -- bash -lc \
        "rabbitmqctl change_password \"${username}\" \"${password}\"" >/dev/null 2>&1
}

rotation_reconcile_secret_backing_resources() {
    local namespace="$1"
    local secret_name="$2"

    local mariadb_users=()
    while IFS= read -r user_name; do
        [[ -n "$user_name" && "$user_name" != "null" ]] && mariadb_users+=("$user_name")
    done < <(rotation_collect_resource_names_for_secret \
        "users.k8s.mariadb.com" \
        "$namespace" \
        ".items[] | select(.spec.passwordSecretKeyRef.name == \"${secret_name}\") | .metadata.name")

    local rabbitmq_users=()
    while IFS= read -r user_name; do
        [[ -n "$user_name" && "$user_name" != "null" ]] && rabbitmq_users+=("$user_name")
    done < <(rotation_collect_resource_names_for_secret \
        "users.rabbitmq.com" \
        "$namespace" \
        ".items[] | select(.spec.importCredentialsSecret.name == \"${secret_name}\") | .metadata.name")

    local user_name
    for user_name in "${mariadb_users[@]}"; do
        log_info "Reconciling MariaDB user ${namespace}/${user_name} for secret ${secret_name}"
        rotation_patch_resource_annotation "users.k8s.mariadb.com" "$namespace" "$user_name" || return $?
        rotation_wait_for_resource_ready "users.k8s.mariadb.com" "$namespace" "$user_name" || return $?
        rotation_wait_for_mariadb_user_password "$namespace" "$user_name" "$secret_name" || return $?
    done

    for user_name in "${rabbitmq_users[@]}"; do
        log_info "Reconciling RabbitMQ user ${namespace}/${user_name} for secret ${secret_name}"
        rotation_patch_resource_annotation "users.rabbitmq.com" "$namespace" "$user_name" || return $?
        rotation_wait_for_resource_ready "users.rabbitmq.com" "$namespace" "$user_name" || return $?
        rotation_apply_rabbitmq_user_password "$namespace" "$user_name" "$secret_name" || return $?
        rotation_wait_for_rabbitmq_user_password "$namespace" "$user_name" "$secret_name" || return $?
    done
}

rotation_reconcile_owned_secrets() {
    local owned_secrets=("$@")
    local secret_ref
    for secret_ref in "${owned_secrets[@]}"; do
        local namespace="${secret_ref%%/*}"
        local secret_name="${secret_ref##*/}"
        rotation_reconcile_secret_backing_resources "$namespace" "$secret_name" || return $?
    done
}

rotation_service_uses_owned_secrets() {
    local svc_yaml_content="$1"
    shift
    local owned_secrets=("$@")
    local count i replace_count j

    count=$(echo "$svc_yaml_content" | yq e '.secrets | length' - 2>/dev/null)
    [[ "$count" == "null" || -z "$count" ]] && count=0

    for (( i=0; i<count; i++ )); do
        local source_secret source_namespace secret_ref
        source_secret=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_secret // \"\"" -)
        source_namespace=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_namespace // .service.namespace // \"openstack\"" -)
        if [[ -n "$source_secret" ]]; then
            secret_ref="${source_namespace}/${source_secret}"
            array_contains "$secret_ref" "${owned_secrets[@]}" && return 0
        fi

        replace_count=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace | length // 0" - 2>/dev/null)
        [[ "$replace_count" == "null" || -z "$replace_count" ]] && replace_count=0
        for (( j=0; j<replace_count; j++ )); do
            local rep_secret rep_namespace rep_ref
            rep_secret=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[${j}].secret // \"\"" -)
            rep_namespace=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[${j}].namespace // .service.namespace // \"openstack\"" -)
            if [[ -n "$rep_secret" ]]; then
                rep_ref="${rep_namespace}/${rep_secret}"
                array_contains "$rep_ref" "${owned_secrets[@]}" && return 0
            fi
        done
    done

    return 1
}

rotation_collect_service_dependencies() {
    local service_name="$1"
    shift
    local candidate_services=("$@")
    local service_yaml
    service_yaml=$(load_service_config "$service_name")

    local candidate
    for candidate in "${candidate_services[@]}"; do
        [[ "$candidate" == "$service_name" ]] && continue

        local candidate_yaml candidate_owned=()
        candidate_yaml=$(load_service_config "$candidate")
        while IFS= read -r candidate_owned_secret; do
            [[ -n "$candidate_owned_secret" ]] && candidate_owned+=("$candidate_owned_secret")
        done < <(rotation_collect_owned_secrets "$candidate_yaml" "$candidate")

        [[ ${#candidate_owned[@]} -eq 0 ]] && continue
        rotation_service_uses_owned_secrets "$service_yaml" "${candidate_owned[@]}" && echo "$candidate"
    done
}

rotation_sort_services() {
    local candidate_services=("$@")
    local pending=("${candidate_services[@]}")
    local ordered=()
    local next_pending=()

    while [[ ${#pending[@]} -gt 0 ]]; do
        local progressed=0
        next_pending=()

        local service_name
        for service_name in "${pending[@]}"; do
            local deps=()
            while IFS= read -r dep; do
                [[ -n "$dep" ]] && deps+=("$dep")
            done < <(rotation_collect_service_dependencies "$service_name" "${candidate_services[@]}")

            local ready=1
            local dep
            for dep in "${deps[@]}"; do
                if array_contains "$dep" "${pending[@]}" && ! array_contains "$dep" "${ordered[@]}"; then
                    ready=0
                    break
                fi
            done

            if [[ "$ready" -eq 1 ]]; then
                ordered+=("$service_name")
                progressed=1
            else
                next_pending+=("$service_name")
            fi
        done

        if [[ "$progressed" -eq 0 ]]; then
            ordered+=("${next_pending[@]}")
            break
        fi

        pending=("${next_pending[@]}")
    done

    printf '%s\n' "${ordered[@]}"
}

rotation_execute_service_reinstall() {
    local service_name="$1"
    local target_service="$2"
    local cmd=("$GENESTACK_INSTALL_BIN" --service "$service_name")

    if [[ "$service_name" == "$target_service" && -n "$CL_OVERRIDE_VERSION" ]]; then
        cmd+=(--version "$CL_OVERRIDE_VERSION")
    fi

    if [[ "$service_name" == "$target_service" && ${#CL_EXTRA_HELM_ARGS[@]} -gt 0 ]]; then
        cmd+=("${CL_EXTRA_HELM_ARGS[@]}")
    fi

    log_header "Reinstalling service '${service_name}' to apply rotated secrets"
    printf '%q ' "${cmd[@]}"
    printf '\n\n'
    "${cmd[@]}"
}

rotation_restart_service_workloads() {
    local service_name="$1"
    local service_yaml service_namespace
    local workloads=()
    local workload

    service_yaml=$(load_service_config "$service_name")
    service_namespace=$(echo "$service_yaml" | yq e '.service.namespace // "openstack"' -)

    while IFS= read -r workload; do
        [[ -n "$workload" ]] && workloads+=("$workload")
    done < <($KUBECTL_BIN get deployment,statefulset,daemonset \
        --namespace "$service_namespace" \
        -l "application=${service_name}" \
        -o name 2>/dev/null)

    if [[ ${#workloads[@]} -eq 0 ]]; then
        log_info "No controller-managed workloads found to restart for '${service_name}'."
        return 0
    fi

    log_header "Restarting workloads for '${service_name}' to pick up rotated secrets"

    for workload in "${workloads[@]}"; do
        log_info "Rolling restart for ${service_namespace}/${workload}"
        $KUBECTL_BIN rollout restart "$workload" --namespace "$service_namespace" >/dev/null 2>&1 || return $?
    done

    for workload in "${workloads[@]}"; do
        log_info "Waiting for ${service_namespace}/${workload} rollout to finish"
        $KUBECTL_BIN rollout status "$workload" --namespace "$service_namespace" --timeout=20m || return $?
    done
}

rotation_execute_for_service() {
    local svc_yaml_content="$1"
    local service_name="$2"
    local owned_secrets=()
    local impacted_services=()
    local execution_order=()

    while IFS= read -r owned_secret; do
        [[ -n "$owned_secret" ]] && owned_secrets+=("$owned_secret")
    done < <(rotation_collect_owned_secrets "$svc_yaml_content" "$service_name")

    while IFS= read -r impacted_service; do
        [[ -n "$impacted_service" ]] && impacted_services+=("$impacted_service")
    done < <(rotation_collect_impacted_services "$service_name" "${owned_secrets[@]}")

    while IFS= read -r ordered_service; do
        [[ -n "$ordered_service" ]] && execution_order+=("$ordered_service")
    done < <(rotation_sort_services "$service_name" "${impacted_services[@]}")

    log_header "Secret rotation plan for '${service_name}'"

    if [[ ${#owned_secrets[@]} -eq 0 ]]; then
        log_warn "No service-owned secrets were detected for '${service_name}'."
        return 0
    fi

    log_info "Service-owned secrets that will be rotated:"
    local owned_secret
    for owned_secret in "${owned_secrets[@]}"; do
        echo "  - ${owned_secret}" >&2
    done

    log_info "Services that will be reinstalled to consume the new secrets:"
    local ordered_service
    for ordered_service in "${execution_order[@]}"; do
        if [[ "$ordered_service" == "$service_name" ]]; then
            echo "  - ${ordered_service} (target service)" >&2
        else
            echo "  - ${ordered_service}" >&2
        fi
    done

    if [[ "${CL_FORCE_YES:-0}" -ne 1 ]] && ! stdin_is_tty; then
        log_error "Secret rotation requires an interactive terminal confirmation."
        return 1
    fi

    if ! prompt_confirm "Proceed with rotating secrets and reinstalling ${#execution_order[@]} service(s)?"; then
        log_warn "Aborted secret rotation for '${service_name}'."
        return 1
    fi

    secret_rotate_for_service "$svc_yaml_content" "$service_name"
    rotation_reconcile_owned_secrets "${owned_secrets[@]}" || return $?

    for ordered_service in "${execution_order[@]}"; do
        rotation_execute_service_reinstall "$ordered_service" "$service_name" || return $?
        rotation_restart_service_workloads "$ordered_service" || return $?
    done

    log_info "Secret rotation completed for '${service_name}'."
    return 0
}

# ── Config Loading ───────────────────────────────────────────────────────────

# Resolve whether a service uses openstack-common or monitoring-common.
# Heuristic: if namespace contains "monitoring" or family is explicitly set.
resolve_common_family() {
    local config_file="$1"
    local family raw
    raw=$(yq e '.service.family' "$config_file" 2>/dev/null)
    # yq returns "''" or 'null' for missing/explicitly-empty family field
    # family: "" means explicit "no common" -> return empty
    # missing / ~ (null) means auto-detect -> check namespace
    if [[ "$raw" == "''" || "$raw" == '""' ]]; then
        # Explicit empty string — no common merge
        echo ""
    else
        local svc_ns
        svc_ns=$(yq e '.service.namespace // ""' "$config_file" 2>/dev/null)
        if [[ "$svc_ns" == *"monitoring"* ]]; then
            echo "monitoring-common"
        else
            echo "openstack-common"
        fi
    fi
}

load_service_config() {
    local service_name="$1"
    local config_file="${GENESTACK_SERVICES_DIR}/${service_name}.yaml"
    local merge_files=()

    if [[ ! -f "$config_file" ]]; then
        log_error "Service config not found: $config_file"
        log_error "Ensure bin/services/${service_name}.yaml exists."
        exit 1
    fi

    # Merge with common defaults
    local common_name
    common_name=$(resolve_common_family "$config_file")
    local common_file="${GENESTACK_SERVICES_DIR}/${common_name}.yaml"
    local override_common_file="${GENESTACK_SERVICE_CONFIG_OVERRIDES_DIR}/${common_name}.yaml"
    local override_service_file="${GENESTACK_SERVICE_CONFIG_OVERRIDES_DIR}/${service_name}.yaml"

    if [[ -f "$common_file" ]]; then
        merge_files+=("$common_file")
    fi

    merge_files+=("$config_file")

    # Allow runtime overrides to replace chart metadata such as repo_url for
    # air-gapped deployments. Common overrides apply broadly; service-specific
    # overrides win last.
    [[ -f "$override_common_file" ]] && merge_files+=("$override_common_file")
    [[ -f "$override_service_file" ]] && merge_files+=("$override_service_file")

    _merge_configs "${merge_files[@]}"
}

# _merge_configs <file> [file...]
# Outputs merged YAML on stdout.
_merge_configs() {
    # Deep-merge an ordered list of YAML files. Later files win.
    yq eval-all '. as $item ireduce ({}; . * $item )' "$@"
}

# ── Version Resolution ──────────────────────────────────────────────────────

resolve_chart_version() {
    local service_name="$1"
    local svc_yaml_content="$2"

    # Check for explicit version in service config
    local explicit_version
    explicit_version=$(echo "$svc_yaml_content" | yq e '.service.version // ""' -)

    if [[ -n "$explicit_version" && "$explicit_version" != "~" ]]; then
        log_info "Version from service config for ${service_name}: ${explicit_version}"
        echo "$explicit_version"
        return
    fi

    # Fall back to helm-chart-versions.yaml
    if [[ ! -f "$CHART_VERSIONS_FILE" ]]; then
        log_warn "Chart versions file not found at ${CHART_VERSIONS_FILE}, installing with latest."
        return
    fi

    local version
    version=$(yq e ".charts.\"${service_name}\" // \"\"" "$CHART_VERSIONS_FILE")
    if [[ -z "$version" ]]; then
        log_warn "No version found for '${service_name}' in ${CHART_VERSIONS_FILE}, installing with latest."
    else
        log_info "Version from helm-chart-versions.yaml for ${service_name}: ${version}"
    fi
    echo "$version"
}

# ── Helm Repo Resolution ────────────────────────────────────────────────────

resolve_helm_repo() {
    local repo_url="$1"
    local repo_name="$2"
    local service_name="$3"

    # Local chart — no remote repo, use on-disk chart directory
    if [[ -z "$repo_url" || "$repo_url" == '""' || "$repo_url" == "~" ]]; then
        local local_path="${GENESTACK_BASE_DIR}/base-helm-configs/${service_name}"
        if [[ -d "$local_path" ]]; then
            HELM_CHART_PATH="${local_path}"
            log_info "Local chart path: ${HELM_CHART_PATH}"
        else
            log_error "Local chart not found at ${local_path} and no chart.repo_url defined. Cannot install."
            exit 1
        fi
        return 0
    fi

    if [[ "$repo_url" == oci://* ]]; then
        # OCI registry — no need to add/update repo.
        # OCI helm chart path is the full registry/repo (e.g. docker.io/envoyproxy/gateway-helm).
        # The version is passed separately via --version flag during helm upgrade/install.
        HELM_CHART_PATH="$repo_url"
        log_info "OCI chart path: ${HELM_CHART_PATH}"
    else
        helm repo add --force-update "$repo_name" "$repo_url" 2>/dev/null || true
        helm repo update --timeout 120s 2>/dev/null || true
        HELM_CHART_PATH="${repo_name}/${service_name}"
        log_info "Helm repo chart path: ${HELM_CHART_PATH}"
    fi
}

# ── Helm Args Building ──────────────────────────────────────────────────────

build_helm_args() {
    # Reads service config and builds array of -f arguments from:
    #   base-overrides → global-overrides → custom-overrides
    #
    # The service config YAML must contain .chart.service_name.
    #
    # Returns: prints alternating "-f" and "<path>" tokens per line for the
    # caller to consume without shell word-splitting.

    local svc_yaml_content="$1"
    local service_name
    service_name=$(echo "$svc_yaml_content" | yq e '.chart.service_name // .service.name' -)
    : "${service_name:=$1}"  # fallback: pass service name directly

    local base_dir="${GENESTACK_BASE_DIR}/base-helm-configs/${service_name}"
    local global_dir="${GENESTACK_OVERRIDES_DIR}/helm-configs/global_overrides"
    local custom_dir="${GENESTACK_OVERRIDES_DIR}/helm-configs/${service_name}"
    local global_enabled
    local raw_val
    raw_val=$(echo "$svc_yaml_content" | yq e '.chart.global_overrides' -)
    if [[ "$raw_val" == "false" ]]; then
        global_enabled="false"
    else
        global_enabled="true"
    fi

    # Base overrides
    if [[ -d "$base_dir" ]]; then
        for f in "$base_dir"/*.yaml; do
            if [[ -f "$f" ]]; then
                echo "-f"
                echo "$f"
            fi
        done
    else
        log_warn "Base override directory not found: $base_dir"
    fi

    # Global overrides
    if [[ "$global_enabled" == "true" && -d "$global_dir" ]]; then
        for f in "$global_dir"/*.yaml; do
            if [[ -f "$f" ]]; then
                echo "-f"
                echo "$f"
            fi
        done
    fi

    # Custom overrides
    if [[ -d "$custom_dir" ]]; then
        for f in "$custom_dir"/*.yaml; do
            if [[ -f "$f" ]]; then
                echo "-f"
                echo "$f"
            fi
        done
    else
        log_warn "Service config directory not found: $custom_dir"
    fi
}

# ── Secret Management ───────────────────────────────────────────────────────

secret_exists() {
    local ns="$1" name="$2"
    $KUBECTL_BIN get secret "$name" --namespace "$ns" &>/dev/null 2>&1
    return $?
}

secret_get() {
    local ns="$1" name="$2" key="$3"
    local raw value
    raw=$($KUBECTL_BIN get secret "$name" --namespace "$ns" -o jsonpath="{.data.${key}}" 2>/dev/null)
    if [[ -n "$raw" ]]; then
        decode_base64 "$raw"
    fi
}

secret_generate() {
    local len="${1:-32}"
    LC_ALL=C tr -dc 'A-Za-z0-9_' < /dev/urandom | head -c "$len"
}

secret_create() {
    local ns="$1" name="$2"
    shift 2

    local cmd_args=( "$@" )
    local has_from_literal=0
    for arg in "${cmd_args[@]}"; do
        if [[ "$arg" == --from-literal=* ]]; then
            has_from_literal=1
        fi
    done

    if [[ $has_from_literal -eq 0 ]]; then
        # No literal key provided — create empty secret, key patched later by secret_ensure
        $KUBECTL_BIN create secret generic "$name" \
            --namespace "$ns" --dry-run=client -o yaml 2>/dev/null | \
            $KUBECTL_BIN apply --namespace "$ns" -f - >/dev/null 2>&1
    else
        $KUBECTL_BIN create secret generic "$name" \
            --namespace "$ns" "$@" \
            --dry-run=client -o yaml 2>/dev/null | \
            $KUBECTL_BIN apply --namespace "$ns" -f - >/dev/null 2>&1
    fi
}

secret_delete() {
    local ns="$1" name="$2"
    log_info "Deleting secret: ${ns}/${name}"
    $KUBECTL_BIN delete secret "$name" --namespace "$ns" 2>/dev/null || true
}

secret_ensure() {
    local ns="$1" name="$2" key="$3" value="$4"
    if secret_exists "$ns" "$name"; then
        local existing
        existing=$(secret_get "$ns" "$name" "$key" 2>/dev/null)
        if [[ -n "$existing" ]]; then
            log_info "Secret ${ns}/${name} key ${key} already exists in k8s."
            return 0
        fi
        # Secret exists but key is missing — patch using kubectl patch
        log_info "Adding key ${key} to existing secret ${ns}/${name}"
        $KUBECTL_BIN patch secret "$name" --namespace "$ns" \
            --type merge --patch "{\"data\":{\"${key}\":\"$(encode_base64_single_line "$value")\"}}" \
            >/dev/null 2>&1
    else
        secret_create "$ns" "$name" --from-literal="${key}=${value}" >/dev/null 2>&1
        return 0
    fi
    # Verify the key is present
    local tries=3
    while [[ $tries -gt 0 ]]; do
        local check_raw
        check_raw=$($KUBECTL_BIN get secret "$name" --namespace "$ns" \
            -o jsonpath="{.data.${key}}" 2>/dev/null)
        if [[ -n "$check_raw" ]]; then
            return 0
        fi
        sleep 1
        tries=$((tries - 1))
    done
    return 1
}

secret_ensure_multi() {
    # Create or verify a secret with multiple key=value pairs.
    # Usage: secret_ensure_multi <ns> <name> key1 val1 [key2 val2 ...]
    local ns="$1" name="$2"; shift 2

    local literal_args=()
    while [[ $# -ge 2 ]]; do
        literal_args+=(--from-literal="$1=$2")
        shift 2
    done

    if secret_exists "$ns" "$name"; then
        log_info "Secret ${ns}/${name} already exists in k8s."
        return 0
    else
        log_info "Creating secret: ${ns}/${name}"
        $KUBECTL_BIN create secret generic "$name" \
            --namespace "$ns" \
            "${literal_args[@]}" \
            --dry-run=client -o yaml | \
            $KUBECTL_BIN apply --namespace "$ns" -f -
    fi
}

secret_key_is_ssh_material() {
    local key_name="$1"
    [[ "$key_name" == "public-key" || "$key_name" == "private-key" || "$key_name" == "public_key" || "$key_name" == "private_key" ]]
}

secret_name_is_rabbitmq_user_credentials() {
    local secret_name="$1"
    [[ "$secret_name" == *-rabbitmq-password ]]
}

secret_rabbitmq_username_from_secret_name() {
    local secret_name="$1"
    echo "${secret_name%-rabbitmq-password}"
}

secret_ensure_rabbitmq_user_credentials() {
    local ns="$1" name="$2"
    local username password

    username=$(secret_rabbitmq_username_from_secret_name "$name")
    password=$(secret_get "$ns" "$name" "password" 2>/dev/null || true)

    if [[ -n "$password" ]]; then
        secret_ensure "$ns" "$name" "username" "$username"
        return 0
    fi

    secret_ensure_multi "$ns" "$name" \
        "username" "$username" \
        "password" "$(secret_generate 32)" >/dev/null 2>&1
}

service_secret_is_ssh_keypair() {
    local svc_yaml_content="$1"
    local secret_name="$2"
    local secret_ns="$3"

    local matched_keys
    matched_keys=$(echo "$svc_yaml_content" | yq e \
        ".secrets[] | select(.source_secret == \"${secret_name}\" and (.source_namespace // \"${secret_ns}\") == \"${secret_ns}\") | .data_key" - 2>/dev/null || true)

    echo "$matched_keys" | grep -Eq '^(public-key|public_key)$' && \
    echo "$matched_keys" | grep -Eq '^(private-key|private_key)$'
}

secret_ensure_ssh_keypair() {
    local ns="$1" name="$2" public_key_name="$3" private_key_name="$4"
    local existing_public existing_private tmp_dir tmp_key_base public_key private_key

    existing_public=$(secret_get "$ns" "$name" "$public_key_name" 2>/dev/null || true)
    existing_private=$(secret_get "$ns" "$name" "$private_key_name" 2>/dev/null || true)

    if [[ -n "$existing_public" && -n "$existing_private" ]]; then
        log_info "SSH keypair secret ${ns}/${name} already exists in k8s."
        return 0
    fi

    log_info "Generating SSH keypair secret: ${ns}/${name}"
    tmp_dir=$(mktemp -d)
    tmp_key_base="${tmp_dir}/${name}"
    ssh-keygen -q -t ed25519 -N '' -C "${name}" -f "${tmp_key_base}" >/dev/null
    public_key=$(cat "${tmp_key_base}.pub")
    private_key=$(cat "${tmp_key_base}")

    if secret_exists "$ns" "$name"; then
        $KUBECTL_BIN patch secret "$name" --namespace "$ns" \
            --type merge --patch "{\"data\":{\"${public_key_name}\":\"$(encode_base64_single_line "$public_key")\",\"${private_key_name}\":\"$(encode_base64_single_line "$private_key")\"}}" \
            >/dev/null 2>&1
    else
        secret_ensure_multi "$ns" "$name" \
            "$public_key_name" "$public_key" \
            "$private_key_name" "$private_key" >/dev/null 2>&1
    fi

    rm -rf "$tmp_dir"
}

secret_rotate_for_service() {
    # Rotate all explicitly-owned secrets listed in a service config.
    local svc_yaml_content="$1"
    local service_name="$2"

    local count
    count=$(echo "$svc_yaml_content" | yq e '.secrets | length' -)
    local rotated_ns_names=()

    for (( i=0; i<count; i++ )); do
        local secret_name secret_ns secret_data_key rotate_with_service
        secret_name=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_secret // \"\"" -)
        secret_ns=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_namespace // .service.namespace // \"openstack\"" -)
        secret_data_key=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].data_key" -)
        rotate_with_service=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].rotate_with_service // false" -)

        [[ "$rotate_with_service" != "true" ]] && continue
        [[ -z "$secret_data_key" ]] && continue

        local key_pair="${secret_ns}/${secret_name}"
        # Avoid rotating same secret twice
        if [[ " ${rotated_ns_names[*]:-} " != *" ${key_pair} "* ]]; then
            rotated_ns_names+=("$key_pair")
        fi
    done

    if [[ ${#rotated_ns_names[@]} -eq 0 ]]; then
        log_info "No service-owned secrets to rotate for '${service_name}'."
        return 0
    fi

    log_header "Rotating ${#rotated_ns_names[@]} secrets for service '${service_name}'"

    for ns_name in "${rotated_ns_names[@]}"; do
        local ns="${ns_name%%/*}"
        local name="${ns_name##*/}"

        secret_delete "$ns" "$name"
        rotation_regenerate_owned_secret "$svc_yaml_content" "$ns" "$name"
    done
}

secret_prepare_for_service() {
    # Resolves all secrets from a service config and returns Helm CLI args.
    # Each line is emitted as: <helm_flag>\t<helm_key>=<resolved-value-or-file>
    local svc_yaml_content="$1"
    local service_name="$2"
    local set_args=()
    local dry_run="$3"  # 1 = --check-secrets mode (do not create missing secrets)
    local had_errors=0

    # Get namespace from service config
    local namespace
    namespace=$(echo "$svc_yaml_content" | yq e '.service.namespace // "openstack"' -)

    local count
    count=$(echo "$svc_yaml_content" | yq e '.secrets | length' -)

    if [[ "$count" -eq 0 ]]; then
        return 0
    fi

    for (( i=0; i<count; i++ )); do
        local helm_key keys_count helm_flag secret_value
        helm_key=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].helm_key" -)
        : "${helm_key:=}"
        if [[ "$helm_key" == "null" ]]; then
            helm_key=""
        fi
        keys_count=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].keys | length // 0" -)
        : "${keys_count:=0}"
        if [[ "$keys_count" == "null" ]]; then
            keys_count=0
        fi
        helm_flag=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].helm_flag" -)
        : "${helm_flag:=--set}"
        if [[ "$helm_flag" == "null" ]]; then
            helm_flag="--set"
        fi
        secret_value=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].value" -)
        : "${secret_value:=}"
        if [[ "$secret_value" == "null" ]]; then
            secret_value=""
        fi

        local secret_name source_secret source_namespace data_key value=""
        secret_name=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].name" -)
        : "${secret_name:=}"
        if [[ "$secret_name" == "null" ]]; then
            secret_name=""
        fi
        source_secret=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_secret" -)
        : "${source_secret:=}"
        if [[ "$source_secret" == "null" ]]; then
            source_secret=""
        fi
        source_namespace=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_namespace" -)
        : "${source_namespace:=$namespace}"
        if [[ "$source_namespace" == "null" ]]; then
            source_namespace="$namespace"
        fi
        data_key=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].data_key" -)
        : "${data_key:=}"
        if [[ "$data_key" == "null" ]]; then
            data_key=""
        fi

        # --- New-style "generate" path: keys{} is present and non-empty ---
        if [[ "$keys_count" -gt 0 && -n "$secret_name" ]]; then
            local secret_ns
            secret_ns=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].namespace" -)
            : "${secret_ns:=$namespace}"
            if [[ "$secret_ns" == "null" ]]; then
                secret_ns="$namespace"
            fi
            local ns="$secret_ns"

            # Determine secret type (use default "Opaque")
            local sec_type
            sec_type=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].type" -)
            : "${sec_type:=Opaque}"
            if [[ "$sec_type" == "null" ]]; then
                sec_type="Opaque"
            fi

            # Iterate map: for each key in .keys{}, get key_name and kv
            while IFS= read -r key_name; do
                [[ -z "$key_name" ]] && continue

                # For helm_key, compose as <helm_key>.<key_name> if helm_key is set
                local this_helm_key=""
                if [[ -n "$helm_key" && "$helm_key" != '""' ]]; then
                    this_helm_key="${helm_key}.${key_name}"
                else
                    this_helm_key="$key_name"
                fi

                # The value from the map is either "generate" or a literal value
                local kv generated_value current_value=""
                kv=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].keys.${key_name}" -)
                : "${kv:=generate}"
                if [[ "$kv" == "null" ]]; then
                    kv="generate"
                fi

                if [[ "$kv" == "generate" ]]; then
                    # Generate a random value
                    generated_value=$(secret_generate 32)

                    if [[ "$dry_run" -eq 1 ]]; then
                        # Check-only mode: do not create
                        if ! secret_exists "$ns" "$secret_name"; then
                            log_warn "Dry-run: secret ${ns}/${secret_name} does not exist, would create with key ${key_name}"
                        fi
                        log_info "DRY-RUN: would generate value for ${this_helm_key} (from ${ns}/${secret_name}:${key_name})"
                        current_value="<generated>"
                    else
                        if ! secret_exists "$ns" "$secret_name"; then
                            $KUBECTL_BIN create secret generic "$secret_name" \
                                --namespace "$ns" --dry-run=client -o yaml 2>/dev/null | \
                                $KUBECTL_BIN apply --namespace "$ns" -f - >/dev/null 2>&1
                            log_info "Created (empty) secret: ${ns}/${secret_name}"
                        fi
                        secret_ensure "$ns" "$secret_name" "$key_name" "$generated_value"
                        current_value="$generated_value"
                    fi
                else
                    # Literal value (not "generate")
                    current_value="$kv"
                    if [[ -z "$current_value" ]]; then
                        log_warn "Empty value for key '${key_name}' in ${ns}/${secret_name}, skipping."
                        continue
                    fi

                    if [[ "$dry_run" -eq 1 ]]; then
                        if ! secret_exists "$ns" "$secret_name"; then
                            log_warn "Dry-run: secret ${ns}/${secret_name} does not exist, would create with key ${key_name}=<literal>"
                        fi
                    else
                        if ! secret_exists "$ns" "$secret_name"; then
                            $KUBECTL_BIN create secret generic "$secret_name" \
                                --namespace "$ns" --dry-run=client -o yaml 2>/dev/null | \
                                $KUBECTL_BIN apply --namespace "$ns" -f - >/dev/null 2>&1
                        fi
                        secret_ensure "$ns" "$secret_name" "$key_name" "$current_value"
                    fi
                fi

                if [[ -n "$current_value" ]]; then
                    set_args+=("$(build_secret_helm_arg "$helm_flag" "$this_helm_key" "$current_value")")
                fi
            done < <(echo "$svc_yaml_content" | yq e ".secrets[${i}].keys | keys | .[]" -)

            continue
        fi

        # --- Legacy "source_secret" path ---
        local value_from_type
        value_from_type=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].value_from.type // \"\"" -)

        if value=$(resolve_secret_value_from_action "$svc_yaml_content" "$i" "$dry_run"); then
            :
        elif [[ -n "$value_from_type" && "$value_from_type" != "null" ]]; then
            had_errors=1
            continue
        elif [[ -n "$source_secret" && "$source_namespace" != '""' && -n "$data_key" ]]; then
            # Standard secret lookup
            if [[ "$dry_run" -eq 1 ]]; then
                # Check-only mode: report but do not create
                if secret_exists "$source_namespace" "$source_secret"; then
                    value=$(secret_get "$source_namespace" "$source_secret" "$data_key")
                    if [[ -z "$value" ]]; then
                        log_error "Missing secret data: ${source_namespace}/${source_secret}:${data_key}"
                        had_errors=1
                    fi
                else
                    log_error "MISSING SECRET: ${source_namespace}/${source_secret}"
                    had_errors=1
                    continue
                fi
            else
                # Normal: ensure secret exists
                if ! secret_exists "$source_namespace" "$source_secret"; then
                    log_info "Secret not found in k8s, generating and creating: ${source_namespace}/${source_secret}"
                    secret_ensure "$source_namespace" "$source_secret" "$data_key" "$(secret_generate 32)"
                fi
                value=$(secret_get "$source_namespace" "$source_secret" "$data_key")
            fi
        elif [[ -n "$secret_value" && "$secret_value" != '""' ]]; then
            # value + replace: templated string with ${TOKEN} substitution
            local replacement_count=0
            local tokens_found
            tokens_found=$(echo "$secret_value" | grep -oE '\$\{[A-Z_]+\}' | sed 's/^\${//;s/}$//' | sort -u) || true
            while IFS= read -r token; do
                [[ -z "$token" ]] && continue
                # Check token actually exists in this entry's replace: array
                local rep_key
                rep_key=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[] | select(.key == \"$token\") | .key" -)
                [[ "$rep_key" == "null" || -z "$rep_key" ]] && continue
                local rep_secret rep_ns rep_data_key rep_val
                rep_secret=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[] | select(.key == \"$token\") | .secret" -)
                : "${rep_secret:=}"
                if [[ "$rep_secret" == "null" ]]; then rep_secret=""; fi
                [[ -z "$rep_secret" ]] && continue
                rep_ns=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[] | select(.key == \"$token\") | .namespace" -)
                : "${rep_ns:=$namespace}"
                if [[ "$rep_ns" == "null" ]]; then rep_ns="$namespace"; fi
                rep_data_key=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[] | select(.key == \"$token\") | .data_key" -)
                if [[ "$dry_run" -eq 1 ]]; then
                    if ! secret_exists "$rep_ns" "$rep_secret"; then
                        log_error "MISSING SECRET: ${rep_ns}/${rep_secret}"
                        had_errors=1
                    fi
                else
                    if ! secret_exists "$rep_ns" "$rep_secret"; then
                        log_info "Secret not found, generating: ${rep_ns}/${rep_secret}"
                        secret_ensure "$rep_ns" "$rep_secret" "$rep_data_key" "$(secret_generate 32)"
                    fi
                fi
                rep_val=$(secret_get "$rep_ns" "$rep_secret" "$rep_data_key")
                if [[ -n "$rep_val" ]]; then
                    secret_value=$(echo "$secret_value" | sed "s|\${${token}}|${rep_val}|g")
                    replacement_count=$((replacement_count + 1))
                else
                    log_error "MISSING SECRET DATA: ${rep_ns}/${rep_secret}:${rep_data_key}"
                    had_errors=1
                fi
            done <<< "$tokens_found"
            if [[ -n "$secret_value" ]]; then
                value="$secret_value"
            else
                log_warn "Template fully unsubstituted for helm_key '${helm_key}', skipping."
                continue
            fi
        else
            log_warn "No data source defined for helm_key '${helm_key}', skipping."
            continue
        fi

        if [[ -n "$value" ]]; then
            set_args+=("$(build_secret_helm_arg "$helm_flag" "$helm_key" "$value")")
        elif [[ "$dry_run" -eq 1 ]]; then
            had_errors=1
        fi
    done

    # Return the array as newline-separated elements
    for arg in "${set_args[@]}"; do
        echo "$arg"
    done

    [[ "$had_errors" -eq 0 ]]
}

# ── Secret Bootstrap ─────────────────────────────────────────────────────────

secret_ensure_service() {
    # Pre-install secret bootstrap: ensures all secrets referenced by a service
    # exist in k8s, auto-generating if missing. This handles circular
    # dependencies (e.g., placement needs nova-db-password, but nova needs
    # placement-admin) by creating all missing secrets on-demand. On re-runs,
    # secret_exists prevents overwriting secrets owned by other services.
    #
    # Usage: secret_ensure_service "$svc_yaml_content" "$service_name"
    local svc_yaml_content="$1"
    local service_name="$2"

    local namespace
    namespace=$(echo "$svc_yaml_content" | yq e '.service.namespace // "openstack"' -)

    local count
    count=$(echo "$svc_yaml_content" | yq e '.secrets | length' -)

    if [[ "$count" -eq 0 ]]; then
        return 0
    fi

    for (( i=0; i<count; i++ )); do
        local source_secret source_namespace data_key secret_value
        source_secret=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_secret" -)
        : "${source_secret:=}"
        if [[ "$source_secret" == "null" ]]; then
            source_secret=""
        fi
        source_namespace=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].source_namespace" -)
        : "${source_namespace:=$namespace}"
        if [[ "$source_namespace" == "null" ]]; then
            source_namespace="$namespace"
        fi
        data_key=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].data_key" -)
        : "${data_key:=}"
        if [[ "$data_key" == "null" ]]; then
            data_key=""
        fi
        secret_value=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].value" -)
        : "${secret_value:=}"
        if [[ "$secret_value" == "null" ]]; then
            secret_value=""
        fi

        # source_secret path: ensure referenced secret exists
        if [[ -n "$source_secret" && -n "$data_key" ]]; then
            if ! secret_exists "$source_namespace" "$source_secret"; then
                if secret_key_is_ssh_material "$data_key" && service_secret_is_ssh_keypair "$svc_yaml_content" "$source_secret" "$source_namespace"; then
                    local public_key_name private_key_name
                    public_key_name=$(echo "$svc_yaml_content" | yq e ".secrets[] | select(.source_secret == \"${source_secret}\" and (.source_namespace // \"${source_namespace}\") == \"${source_namespace}\" and (.data_key == \"public-key\" or .data_key == \"public_key\")) | .data_key" - | head -n1)
                    private_key_name=$(echo "$svc_yaml_content" | yq e ".secrets[] | select(.source_secret == \"${source_secret}\" and (.source_namespace // \"${source_namespace}\") == \"${source_namespace}\" and (.data_key == \"private-key\" or .data_key == \"private_key\")) | .data_key" - | head -n1)
                    secret_ensure_ssh_keypair "$source_namespace" "$source_secret" "$public_key_name" "$private_key_name"
                elif secret_name_is_rabbitmq_user_credentials "$source_secret"; then
                    log_info "Pre-creating RabbitMQ credentials secret: ${source_namespace}/${source_secret}"
                    secret_ensure_rabbitmq_user_credentials "$source_namespace" "$source_secret"
                else
                    log_info "Pre-creating secret: ${source_namespace}/${source_secret}"
                    secret_ensure "$source_namespace" "$source_secret" "$data_key" "$(secret_generate 32)"
                fi
            elif secret_key_is_ssh_material "$data_key" && service_secret_is_ssh_keypair "$svc_yaml_content" "$source_secret" "$source_namespace"; then
                local public_key_name private_key_name
                public_key_name=$(echo "$svc_yaml_content" | yq e ".secrets[] | select(.source_secret == \"${source_secret}\" and (.source_namespace // \"${source_namespace}\") == \"${source_namespace}\" and (.data_key == \"public-key\" or .data_key == \"public_key\")) | .data_key" - | head -n1)
                private_key_name=$(echo "$svc_yaml_content" | yq e ".secrets[] | select(.source_secret == \"${source_secret}\" and (.source_namespace // \"${source_namespace}\") == \"${source_namespace}\" and (.data_key == \"private-key\" or .data_key == \"private_key\")) | .data_key" - | head -n1)
                secret_ensure_ssh_keypair "$source_namespace" "$source_secret" "$public_key_name" "$private_key_name"
            elif secret_name_is_rabbitmq_user_credentials "$source_secret"; then
                secret_ensure_rabbitmq_user_credentials "$source_namespace" "$source_secret"
            fi
        fi

        # value + replace: path: ensure each replaced secret exists
        if [[ -n "$secret_value" && "$secret_value" != '""' ]]; then
            local tokens_found
            tokens_found=$(echo "$secret_value" | grep -oE '\$\{[A-Z_]+\}' | sed 's/^\${//;s/}$//' | sort -u) || true
            while IFS= read -r token; do
                [[ -z "$token" ]] && continue
                local rep_secret rep_ns rep_data_key
                rep_secret=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[] | select(.key == \"$token\") | .secret" -)
                : "${rep_secret:=}"
                if [[ "$rep_secret" == "null" ]]; then rep_secret=""; fi
                [[ -z "$rep_secret" ]] && continue
                rep_ns=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[] | select(.key == \"$token\") | .namespace" -)
                : "${rep_ns:=$namespace}"
                if [[ "$rep_ns" == "null" ]]; then rep_ns="$namespace"; fi
                rep_data_key=$(echo "$svc_yaml_content" | yq e ".secrets[${i}].replace[] | select(.key == \"$token\") | .data_key" -)
                if [[ -n "$rep_data_key" ]]; then
                    if ! secret_exists "$rep_ns" "$rep_secret"; then
                        log_info "Pre-creating secret: ${rep_ns}/${rep_secret}"
                        secret_ensure "$rep_ns" "$rep_secret" "$rep_data_key" "$(secret_generate 32)"
                    fi
                fi
            done <<< "$tokens_found"
        fi
    done
}

# ── Temp File Management ─────────────────────────────────────────────────────

mk_tmp_file() {
    local tmp
    tmp=$(mktemp)
    TMP_FILES+=("$tmp")
    echo "$tmp"
}

cleanup_tmp() {
    for f in "${TMP_FILES[@]}"; do
        rm -f "$f" 2>/dev/null || true
    done
}

# ── Kubernetes Operations ────────────────────────────────────────────────────

ensure_namespace() {
    local ns="$1"
    if $KUBECTL_BIN get namespace "$ns" &>/dev/null 2>&1; then
        log_info "Namespace '${ns}' already exists."
    else
        log_info "Creating namespace: ${ns}"
        $KUBECTL_BIN create namespace "$ns"
    fi
}

label_namespace_for_talos() {
    local ns="$1"
    local labels=(
        "pod-security.kubernetes.io/enforce=privileged"
        "pod-security.kubernetes.io/audit=privileged"
        "pod-security.kubernetes.io/warn=privileged"
    )
    $KUBECTL_BIN label namespace "$ns" "${labels[@]}" --overwrite 2>/dev/null || true
}

copy_secret_between_namespaces() {
    local src_ns="$1" dst_ns="$2" name="$3"
    local yaml
    yaml=$($KUBECTL_BIN get secret "$name" --namespace "$src_ns" -o yaml 2>/dev/null)
    if [[ -z "$yaml" ]]; then
        log_error "Source secret ${src_ns}/${name} not found, cannot copy."
        return 1
    fi
    # Remove resourceVersion, uid, creationTimestamp, etc.
    yaml=$(echo "$yaml" | yq e 'del(.metadata.resourceVersion, .metadata.uid, .metadata.creationTimestamp, .metadata.selfLink) | .metadata.namespace = "${dst_ns}"' -)
    echo "$yaml" | $KUBECTL_BIN apply --namespace "$dst_ns" -f -
}

ensure_ovn_client_tls_secret() {
    local src_ns="${1:-kube-system}"
    local dst_ns="${2:-openstack}"
    local src_name="${3:-kube-ovn-tls}"
    local dst_name="${4:-ovn-client-tls}"

    if ! $KUBECTL_BIN get secret "$src_name" --namespace "$src_ns" >/dev/null 2>&1; then
        log_warn "OVN TLS source secret ${src_ns}/${src_name} not found; skipping ${dst_ns}/${dst_name} sync."
        return 0
    fi

    log_info "Syncing OVN TLS secret ${src_ns}/${src_name} to ${dst_ns}/${dst_name}"
    $KUBECTL_BIN get secret "$src_name" --namespace "$src_ns" -o yaml \
        | yq e 'del(.metadata.resourceVersion, .metadata.uid, .metadata.creationTimestamp, .metadata.selfLink, .metadata.annotations."kubectl.kubernetes.io/last-applied-configuration") | .metadata.namespace = "'"${dst_ns}"'" | .metadata.name = "'"${dst_name}"'"' - \
        | $KUBECTL_BIN apply --namespace "$dst_ns" -f -
}

# ── OVN TLS Detection ────────────────────────────────────────────────────────

detect_kube_ovn_tls() {
    # Checks if kube-ovn has TLS enabled. Returns "ssl" or "tcp".
    # Also sets $OVN_NB_IP, $OVN_NB_PORT, $OVN_SB_IP, $OVN_SB_PORT.
    local kube_ovn_tls="false"
    local enable_ssl
    enable_ssl=$($KUBECTL_BIN -n kube-system get deploy ovn-central \
        -o jsonpath='{.spec.template.spec.containers[0].env[?(@.name=="ENABLE_SSL")].value}' 2>/dev/null || true)

    if [[ "$enable_ssl" == "true" || "$enable_ssl" == "True" ]]; then
        kube_ovn_tls="true"
    fi

    if [[ "$kube_ovn_tls" == "true" ]]; then
        CONNECTION_STRING="ssl"
    else
        CONNECTION_STRING="tcp"
    fi

    # OVN service discovery
    OVN_NB_IP=$($KUBECTL_BIN -n kube-system get service ovn-nb -o jsonpath='{.spec.clusterIP}' 2>/dev/null)
    OVN_NB_PORT=$($KUBECTL_BIN -n kube-system get service ovn-nb -o jsonpath='{.spec.ports[0].port}' 2>/dev/null)
    OVN_SB_IP=$($KUBECTL_BIN -n kube-system get service ovn-sb -o jsonpath='{.spec.clusterIP}' 2>/dev/null)
    OVN_SB_PORT=$($KUBECTL_BIN -n kube-system get service ovn-sb -o jsonpath='{.spec.ports[0].port}' 2>/dev/null)

    if [[ -n "$OVN_NB_IP" && -n "$OVN_NB_PORT" && -n "$OVN_SB_IP" && -n "$OVN_SB_PORT" ]]; then
        OVN_NB_CONNECTION="${CONNECTION_STRING}:${OVN_NB_IP}:${OVN_NB_PORT}"
        OVN_SB_CONNECTION="${CONNECTION_STRING}:${OVN_SB_IP}:${OVN_SB_PORT}"
        export CONNECTION_STRING OVN_NB_CONNECTION OVN_SB_CONNECTION OVN_NB_IP OVN_NB_PORT OVN_SB_IP OVN_SB_PORT
    else
        OVN_NB_CONNECTION=""
        OVN_SB_CONNECTION=""
        export CONNECTION_STRING OVN_NB_CONNECTION OVN_SB_CONNECTION
        log_warn "Could not resolve OVN service addresses, skipping OVN connection string injection."
    fi
}

# ── Helm Execution ───────────────────────────────────────────────────────────

exec_helm() {
    # Builds and executes the final helm upgrade --install command.
    # Expects the caller to populate:
    #   HELM_CMD_ARRAY    — array of all helm args (including -f and --set entries)
    local service_name="$1"
    local service_version="$2"
    local service_namespace="$3"
    shift 3

    local helm_args=("$@")

    log_header "Executing helm for ${service_name}"

    # Print safe debug output
    log_info "Helm command: helm upgrade --install ${helm_args[*]}"

    if [[ "${CL_DRY_RUN:-0}" -eq 1 ]]; then
        log_info "DRY RUN — skipping execution."
        return 0
    fi

    helm upgrade --install "$service_name" \
        "${helm_args[@]}"
}

helm_install_crds() {
    # Install CRD chart first (e.g. mariadb-operator-crds), then main chart.
    local service_name="$1"
    local crd_name="$2"
    local crd_version="$3"
    local crd_repo_name="$4"
    local crd_repo_url="$5"
    local timeout="$6"

    helm repo add --force-update "$crd_repo_name" "$crd_repo_url" 2>/dev/null || true
    helm repo update --timeout 120s 2>/dev/null || true

    helm upgrade --install "$crd_name" "${crd_repo_name}/${crd_name}" \
        --version "${crd_version}" \
        --namespace kube-system \
        --create-namespace \
        --timeout "$timeout"
}

multi_chart_install() {
    # Generic multi-chart installer for services that deploy multiple charts
    # (e.g., redis-operator installs both operator and replication).
    # The service config should have a .multi_charts array:
    #   multi_charts:
    #     - release_name: redis-operator
    #       chart: redis-operator
    #       repo_name: ot-helm
    #       repo_url: https://ot-container-kit.github.io/helm-charts
    #       namespace: redis-systems
    #     - release_name: redis-replication
    #       chart: redis-replication
    #       repo_name: ot-helm
    #       repo_url: https://ot-container-kit.github.io/helm-charts
    #       namespace: redis-systems
    local svc_yaml_content="$1"
    local service_name="$2"
    local version="$3"
    local timeout="$4"
    local override_lines="$5"
    local set_args_raw="$6"
    local post_renderer_args="$7"

    local chart_count
    chart_count=$(echo "$svc_yaml_content" | yq e '.multi_charts | length' -)

    if [[ "$chart_count" -eq 0 ]]; then
        log_error "multi_chart_install called but no multi_charts defined for ${service_name}."
        exit 1
    fi

    for (( i=0; i<chart_count; i++ )); do
        local release_name chart repo_name repo_url namespace
        release_name=$(echo "$svc_yaml_content" | yq e ".multi_charts[${i}].release_name" -)
        chart=$(echo "$svc_yaml_content" | yq e ".multi_charts[${i}].chart" -)
        repo_name=$(echo "$svc_yaml_content" | yq e ".multi_charts[${i}].repo_name" -)
        repo_url=$(echo "$svc_yaml_content" | yq e ".multi_charts[${i}].repo_url" -)
        namespace=$(echo "$svc_yaml_content" | yq e ".multi_charts[${i}].namespace" -)
        : "${namespace:=$service_name}"

        log_header "Installing chart [${i}]: ${release_name}"

        ensure_namespace "$namespace"
        label_namespace_for_talos "$namespace"

        resolve_helm_repo "$repo_url" "$repo_name" "$chart"

        if [[ "${CL_DRY_RUN:-0}" -eq 1 ]]; then
            continue
        fi

        local helm_cmd=()
        while IFS= read -r token; do
            [[ -z "$token" ]] && continue
            helm_cmd+=("$token")
        done < <(build_helm_upgrade_install_cmd \
            "$release_name" \
            "$HELM_CHART_PATH" \
            "$namespace" \
            "$version" \
            "$timeout" \
            "$override_lines" \
            "$set_args_raw" \
            "$post_renderer_args" \
            "${CL_EXTRA_HELM_ARGS[@]}")

        printf '%q ' "${helm_cmd[@]}"
        printf '\n\n'
        "${helm_cmd[@]}"
    done
}

# ── Trap / Cleanup ───────────────────────────────────────────────────────────

_setup_cleanup_trap() {
    trap 'cleanup_tmp' EXIT INT TERM
}
